INSERT INTO `b_thing` VALUES (81, '英寸笔记本电脑包,黑色', 'b5de8200-ff15-4574-8e38-7642fe952f77.jpeg', '关于配送时间的预估仅供参考，实际配送受清关或天气等不可抗力因素的影响，您可在“我的订单”中跟踪包裹查看配送状态，如有疑问请联系客服咨询。\r\n• 亚马逊海外购商品符合海关进出口政策要求，且支持中国除港澳台地区之外的全境配送，但部分偏远地区的配送时间会相应延长，少数商品不支持配送。如果您已成功下单而我们无法为您配送，我们会及时通知您。\r\n• 亚马逊海外购商品目前不支持晚间送货、预约送货、自提等服务。', '321', '0', 333, 0, '2023-03-22 20:29:00.305841', 0, 0, 2, 3, 6);
